.darma-loader-darma-custom-381 {color: var(--loader-color, #2563eb);
  height: 64px;
  aspect-ratio: 2;
  display: grid;
  grid-template-columns: 1fr 1fr;
}.darma-loader-darma-custom-381:before,.darma-loader-darma-custom-381:after {content: "";
  border: 8px solid var(--loader-color, #2563eb);
  box-sizing: content-box;
  margin: auto;
  aspect-ratio: 1;
  animation:darma-loader-darma-custom-381-l10-0 infinite .5s steps(4,jump-none) alternate,darma-loader-darma-custom-381-l10-1 infinite 2s steps(2,jump-none);
}.darma-loader-darma-custom-381:before {animation-delay: -.3s;
}@keyframes darma-loader-darma-custom-381-l10-0 {0% {width: 0% }to {width: 75%}}@keyframes darma-loader-darma-custom-381-l10-1 {0% {border-radius: 0% }to {border-radius: 100%}}

